mapper.update:
UPDATE staff_service_skill
proficiency_level = #{proficiencyLevel}, certificate_url = #{certificateUrl}, certificate_status = #{certificateStatus}, experience_years = #{experienceYears},
WHERE skill_id = #{skillId}

mapper.select:
SELECT skill_id, staff_id, service_id, proficiency_level, certificate_url, certificate_status, experience_years,
       create_time, update_time
FROM staff_service_skill

    AND certificate_status = #{certificateStatus}
    AND staff_id = #{staffId}

ORDER BY update_time DESC
